type testChallengeExtensions struct {
	scope string
}

// Minimal implementation of ChallengeExtensions interface
func (tce *testChallengeExtensions) GetScope() string {
	return tce.scope
}

func (tce *testChallengeExtensions) GetAllowReuse() string {
	return "NO"
}

