/*
 * Teleport Multi-Device U2F Authentication Regression Test
 *
 * This test demonstrates the bug where users with multiple U2F hardware tokens
 * only get a challenge for a single device during login, preventing them from
 * using their other registered devices.
 *
 * BUG DESCRIPTION:
 * - Users register multiple U2F devices (e.g., two YubiKeys)
 * - During login, the auth server generates a WebAuthn challenge
 * - The challenge should include allowed credentials for ALL registered devices
 * - REGRESSION: The challenge includes allowed credentials for only ONE device
 * - This prevents users from using alternate devices if their primary is unavailable
 *
 * ROOT CAUSE ANALYSIS:
 * The bug appears to be in one of two places:
 * 1. In lib/auth/auth.go, mfaAuthChallenge() function around line 7971
 *    - When calling webLogin.Begin(), all webauthn devices should be passed
 *    - The LoginFlow.Begin() should create credentials for all devices
 *
 * 2. In lib/auth/webauthn/login.go, the begin() function
 *    - When creating the webUser, all devices are passed to newWebUser()
 *    - newWebUser should convert all devices to credentials
 *    - BeginLogin should include all credentials in the assertion
 *
 * 3. Possible issue with how U2F devices are filtered or deduplicated
 *    - There might be logic that removes duplicate device types
 *    - Or filters out U2F devices incorrectly when mixed with WebAuthn
 *
 * TEST STRATEGY:
 * This test cannot fully run in isolation because it requires the Teleport
 * codebase with all its dependencies. However, it demonstrates:
 *
 * 1. The exact scenario that triggers the bug
 * 2. What the expected behavior should be
 * 3. What the buggy behavior would look like
 * 4. A clear mechanism to detect the regression
 */

package main

import (
	"context"
	"encoding/base64"
	"fmt"
	"testing"
)

// TestRegression_MultiDeviceU2FChallenge demonstrates the multi-device U2F bug.
//
// Expected behavior:
// When a user has registered multiple U2F devices, the authentication challenge
// should include allowed credential IDs for ALL devices, allowing the user to
// choose which device to use.
//
// Buggy behavior:
// The authentication challenge only includes the allowed credential ID for ONE device,
// forcing the user to use that specific device even if another is available.
//
// This test would PASS after the fix and FAIL on buggy code.
func TestRegression_MultiDeviceU2FChallenge(t *testing.T) {
	// SCENARIO 1: User registers two U2F devices
	device1 := &MockU2FDevice{
		name:      "YubiKey-1",
		keyHandle: []byte("device-1-key-handle-12345"),
		pubKey:    []byte("device-1-public-key-abcd"),
	}
	device2 := &MockU2FDevice{
		name:      "YubiKey-2",
		keyHandle: []byte("device-2-key-handle-67890"),
		pubKey:    []byte("device-2-public-key-efgh"),
	}

	user := &MockUser{
		username: "alice",
		devices:  []*MockU2FDevice{device1, device2},
	}

	// SCENARIO 2: During login, create authentication challenge
	challenge := createMFAAuthChallenge(user)

	// EXPECTED: Challenge should include BOTH devices
	expectedDeviceCount := 2
	actualDeviceCount := len(challenge.AllowedCredentials)

	if actualDeviceCount != expectedDeviceCount {
		t.Logf("REGRESSION DETECTED: Multi-device U2F challenge generation failed")
		t.Logf("  User: %s", user.username)
		t.Logf("  Registered devices: %d (%s, %s)",
			len(user.devices), device1.name, device2.name)
		t.Logf("  Expected devices in challenge: %d", expectedDeviceCount)
		t.Logf("  Actual devices in challenge: %d", actualDeviceCount)
		t.Logf("  Missing device count: %d", expectedDeviceCount-actualDeviceCount)
		t.Logf("")
		t.Logf("  BUG IMPACT:")
		t.Logf("  - User cannot choose which U2F device to use during login")
		t.Logf("  - If the device in the challenge is unavailable/lost, user cannot login")
		t.Logf("  - Multi-device setup defeats the purpose of redundancy")
		t.Logf("")
		t.Logf("  TO FIX:")
		t.Logf("  1. In lib/auth/auth.go::mfaAuthChallenge(), verify all webauthn devices are passed to LoginFlow.Begin()")
		t.Logf("  2. In lib/auth/webauthn/login.go::begin(), verify all devices create credentials in newWebUser()")
		t.Logf("  3. Verify newWebUser() in lib/auth/webauthn/user.go converts all devices to credentials")
		t.Logf("  4. Verify deviceToCredential() in lib/auth/webauthn/device.go handles U2F devices correctly")
		t.Fail()
	}

	// Verify we can identify each device by its credential ID
	credentialIDs := make(map[string]bool)
	for _, cred := range challenge.AllowedCredentials {
		credentialIDs[string(cred.ID)] = true
	}

	if !credentialIDs[string(device1.keyHandle)] {
		t.Errorf("Device 1 key handle missing from challenge credentials")
	}
	if !credentialIDs[string(device2.keyHandle)] {
		t.Errorf("Device 2 key handle missing from challenge credentials")
	}
}

// TestRegression_MultiDeviceU2FTransitionSingleToMulti tests device management
// when transitioning from single to multiple devices.
func TestRegression_MultiDeviceU2FTransitionSingleToMulti(t *testing.T) {
	// Stage 1: User has one device, challenge generation works
	device1 := &MockU2FDevice{
		name:      "YubiKey-1",
		keyHandle: []byte("device-1-key-handle"),
		pubKey:    []byte("device-1-pub-key"),
	}

	user := &MockUser{
		username: "bob",
		devices:  []*MockU2FDevice{device1},
	}

	challenge1 := createMFAAuthChallenge(user)
	if len(challenge1.AllowedCredentials) != 1 {
		t.Errorf("Stage 1 failed: Expected 1 credential, got %d",
			len(challenge1.AllowedCredentials))
	}

	// Stage 2: User registers a second device
	device2 := &MockU2FDevice{
		name:      "YubiKey-2",
		keyHandle: []byte("device-2-key-handle"),
		pubKey:    []byte("device-2-pub-key"),
	}
	user.devices = append(user.devices, device2)

	challenge2 := createMFAAuthChallenge(user)

