// TestRegression_MultiDeviceU2FAuthenticationChallenge tests that multiple U2F devices
// registered by a user all receive challenge credentials during login.
//
// This is a regression test for the issue where users with multiple U2F hardware tokens
// only get a challenge for a single device during login, preventing them from using
// their other registered devices.
func TestRegression_MultiDeviceU2FAuthenticationChallenge(t *testing.T) {
	ctx := context.Background()

	// Create two separate U2F devices
	u2fKey1, err := mocku2f.Create()
	require.NoError(t, err)
	u2fKey1.SetCounter(10)

	u2fKey2, err := mocku2f.Create()
	require.NoError(t, err)
	u2fKey2.SetCounter(20)

	// Convert mock keys to MFA devices
	dev1 := keyToU2FMFADevice("u2f-device-1", u2fKey1, time.Now().Add(-5*time.Minute))
	dev2 := keyToU2FMFADevice("u2f-device-2", u2fKey2, time.Now().Add(-5*time.Minute))

	// Create identity with both devices registered
	identity := newTestIdentity("testuser", dev1, dev2)

	// Create login flow with U2F and WebAuthn config
	u2fConfig := &types.U2F{AppID: "https://example.com:3080"}
	webConfig := &types.Webauthn{RPID: "example.com"}

	webLogin := &webauthn.LoginFlow{
		U2F:      u2fConfig,
		Webauthn: webConfig,
		Identity: identity,
	}

	// Test: Begin login challenge generation
	// This should create a challenge with credentials for BOTH devices
	assertion, err := webLogin.Begin(ctx, webauthn.BeginParams{
		User: "testuser",
		ChallengeExtensions: &testChallengeExtensions{
			scope: "login",
		},
	})
	require.NoError(t, err, "Failed to begin login challenge")
	require.NotNil(t, assertion, "Assertion should not be nil")

	// Extract allowed credential IDs from the assertion
	allowedCredentials := assertion.Response.AllowedCredentials
	require.NotEmpty(t, allowedCredentials, "Allowed credentials should not be empty")

	// BUG: This test will FAIL if only one device is in the challenge
	// The regression is that allowedCredentials contains only 1 ID instead of 2
	require.Len(t, allowedCredentials, 2,
		"Challenge should include credentials for BOTH registered U2F devices. "+
			"BUG: Only %d device(s) present in challenge instead of 2. "+
			"This prevents users from choosing which device to use.", len(allowedCredentials))

	// Verify that both device key handles are in the allowed credentials
	keyHandle1 := u2fKey1.KeyHandle
	keyHandle2 := u2fKey2.KeyHandle
	var foundKey1, foundKey2 bool

	for _, cred := range allowedCredentials {
		if len(cred.CredentialID) > 0 {
			// Check if this credential ID matches either device's key handle
			if string(cred.CredentialID) == string(keyHandle1) {
				foundKey1 = true
			}
			if string(cred.CredentialID) == string(keyHandle2) {
				foundKey2 = true
			}
		}
	}

	require.True(t, foundKey1, "First U2F device key handle not found in challenge credentials")
	require.True(t, foundKey2, "Second U2F device key handle not found in challenge credentials")
}

// TestRegression_MultiDeviceU2FWebAuthnCompatibility tests that both old and new
// clients can properly negotiate multi-device U2F challenges.
func TestRegression_MultiDeviceU2FWebAuthnCompatibility(t *testing.T) {
	ctx := context.Background()

	// Create a user with multiple U2F devices (legacy) and WebAuthn devices (new)
	u2fKey1, err := mocku2f.Create()
	require.NoError(t, err)
	u2fKey1.SetCounter(10)

	u2fKey2, err := mocku2f.Create()
	require.NoError(t, err)
	u2fKey2.SetCounter(20)

	// Create WebAuthn device (newer standard)
	webKey, err := mocku2f.Create()
	require.NoError(t, err)
	webKey.PreferRPID = true
	webKey.SetCounter(30)

	dev1 := keyToU2FMFADevice("u2f-device-1", u2fKey1, time.Now().Add(-5*time.Minute))
	dev2 := keyToU2FMFADevice("u2f-device-2", u2fKey2, time.Now().Add(-5*time.Minute))
	devWeb := keyToWebauthnMFADevice("webauthn-device", webKey, time.Now().Add(-5*time.Minute))

	// Create identity with mixed device types
	identity := newTestIdentity("testuser", dev1, dev2, devWeb)

	// Create login flow
	u2fConfig := &types.U2F{AppID: "https://example.com:3080"}
	webConfig := &types.Webauthn{RPID: "example.com"}

	webLogin := &webauthn.LoginFlow{
		U2F:      u2fConfig,
		Webauthn: webConfig,
		Identity: identity,
	}

	// Generate challenge with mixed device types
	assertion, err := webLogin.Begin(ctx, webauthn.BeginParams{
		User: "testuser",
		ChallengeExtensions: &testChallengeExtensions{
			scope: "login",
		},
	})
	require.NoError(t, err)
	require.NotNil(t, assertion)

	// All three devices should be in the challenge
	allowedCredentials := assertion.Response.AllowedCredentials
	require.Len(t, allowedCredentials, 3,
		"Challenge should include ALL devices (2 U2F + 1 WebAuthn). "+
			"BUG: Only %d device(s) present in challenge instead of 3.", len(allowedCredentials))
}

// TestRegression_MultiDeviceU2FDeletion tests that deleting one U2F device
// when multiple are registered works correctly and doesn't break authentication.
func TestRegression_MultiDeviceU2FDeletion(t *testing.T) {
	ctx := context.Background()

	// Create three U2F devices
	u2fKey1, err := mocku2f.Create()
	require.NoError(t, err)
	u2fKey1.SetCounter(10)

	u2fKey2, err := mocku2f.Create()
	require.NoError(t, err)
	u2fKey2.SetCounter(20)

	u2fKey3, err := mocku2f.Create()
	require.NoError(t, err)
	u2fKey3.SetCounter(30)

	dev1 := keyToU2FMFADevice("u2f-device-1", u2fKey1, time.Now().Add(-5*time.Minute))
	dev2 := keyToU2FMFADevice("u2f-device-2", u2fKey2, time.Now().Add(-5*time.Minute))
	dev3 := keyToU2FMFADevice("u2f-device-3", u2fKey3, time.Now().Add(-5*time.Minute))

	// Create identity with all three devices
	identity := newTestIdentity("testuser", dev1, dev2, dev3)

	// Initial challenge with 3 devices
	u2fConfig := &types.U2F{AppID: "https://example.com:3080"}
	webConfig := &types.Webauthn{RPID: "example.com"}

	webLogin := &webauthn.LoginFlow{
		U2F:      u2fConfig,
		Webauthn: webConfig,
		Identity: identity,
	}

	assertion, err := webLogin.Begin(ctx, webauthn.BeginParams{
		User: "testuser",
		ChallengeExtensions: &testChallengeExtensions{
			scope: "login",
		},
	})
	require.NoError(t, err)
	require.Len(t, assertion.Response.AllowedCredentials, 3)

	// Simulate deletion of one device by creating a new identity without it
	identity2 := newTestIdentity("testuser", dev1, dev3) // Remove dev2

	webLogin2 := &webauthn.LoginFlow{
		U2F:      u2fConfig,
		Webauthn: webConfig,
		Identity: identity2,
	}

	// Challenge should now have 2 devices
	assertion2, err := webLogin2.Begin(ctx, webauthn.BeginParams{
		User: "testuser",
		ChallengeExtensions: &testChallengeExtensions{
			scope: "login",
		},
	})
	require.NoError(t, err)
	require.Len(t, assertion2.Response.AllowedCredentials, 2,
		"After deleting one device, challenge should have 2 devices but has %d",
		len(assertion2.Response.AllowedCredentials))
}

// Helper functions

func keyToU2FMFADevice(name string, key *mocku2f.Key, timestamp time.Time) *types.MFADevice {
	pubKeyDER, err := x509.MarshalPKIXPublicKey(&key.PrivateKey.PublicKey)
	if err != nil {
		panic(err)
	}
	return &types.MFADevice{
		Metadata: types.Metadata{
			Name: name,
		},
		AddedAt:  timestamp,
		LastUsed: timestamp,
		Device: &types.MFADevice_U2F{
			U2F: &types.U2FDevice{
				KeyHandle: key.KeyHandle,
				PubKey:    pubKeyDER,
				Counter:   key.Counter(),
			},
		},
	}
}

func keyToWebauthnMFADevice(name string, key *mocku2f.Key, timestamp time.Time) *types.MFADevice {
	// For WebAuthn devices, we'd need to set up the device differently
	// This is a simplified version for testing purposes
	return &types.MFADevice{
		Metadata: types.Metadata{
			Name: name,
		},
		AddedAt:  timestamp,
		LastUsed: timestamp,
		Device: &types.MFADevice_Webauthn{
			Webauthn: &types.WebauthnDevice{
				CredentialId:     key.KeyHandle,
				CredentialRpId:   "example.com",
				ResidentKey:      false,
				SignatureCounter: key.Counter(),
			},
		},
	}
}

